declare const tools: { mcp__codebase_memory_mcp__search_graph(args: {
  exclude_entry_points?: boolean;
  file_pattern?: string;
  include_connected?: boolean;
  label?: string;
  // Max results per call. Default 200. Response carries 'total' (full match count) and 'has_more' (true if truncated) so callers can detect the limit and paginate.
  limit?: number;
  max_degree?: number;
  min_degree?: number;
  name_pattern?: string;
  // Skip the first N matching nodes. Combine with 'limit' to page: increment offset by limit and re-call while has_more is true.
  offset?: number;
  project: string;
  qn_pattern?: string;
  // Natural-language or keyword full-text search using BM25 ranking. Tokens are split on whitespace; camelCase identifiers are indexed as individual words (updateCloudClient → update, cloud, client). Results are ranked with structural boosting: Functions/Methods +10, Routes +8, Classes/Interfaces +5. Noise labels (File/Folder/Module/Variable) are filtered out. When provided, name_pattern is ignored.
  query?: string;
  relationship?: string;
  // MUST be an ARRAY of keyword strings (e.g. ["send","pubsub","publish"]) — NOT a single string. Each keyword is scored independently via per-keyword min-cosine; results reflect functions that score well on ALL keywords. Requires moderate/full index mode. Results appear in the 'semantic_results' field (separate from 'results').
  semantic_query?: Array<string>;
}): Promise<CallToolResult>; };
